@using sv_149b435869b64d94925f11192099711f.Models

<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var status = GetStatus(stepIndex);
        <button class="step @status"
                disabled="@(status == "future")"
                @onclick="() => OnStepClicked(stepIndex)"
                aria-current="@(stepIndex == CurrentStep ? "step" : null)">
            <span class="step-badge">
                @if (status == "completed")
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </span>
            <span class="step-label">@StepNames[stepIndex]</span>
        </button>
        @if (stepIndex < StepNames.Length - 1)
        {
            <span class="step-connector @(stepIndex < CurrentStep ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
        { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnNavigate { get; set; }

    private string GetStatus(int step) =>
        step == CurrentStep ? "active" :
        step < CurrentStep ? "completed" : "future";

    private async Task OnStepClicked(int step)
    {
        if (step < CurrentStep)
            await OnNavigate.InvokeAsync(step);
    }
}

@using sv_149b435869b64d94925f11192099711f.Models

<h3>Personal Information</h3>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="mb-3">
    <label class="form-label">Full Name *</label>
    <input class="form-control" @bind="Model.FullName" placeholder="Jane Doe" />
</div>

<div class="mb-3">
    <label class="form-label">Email *</label>
    <input type="email" class="form-control" @bind="Model.Email" placeholder="jane@example.com" />
</div>

<div class="mb-3">
    <label class="form-label">Phone *</label>
    <input type="tel" class="form-control" @bind="Model.Phone" placeholder="(555) 123-4567" />
</div>

<div class="mb-3">
    <label class="form-label">Address *</label>
    <textarea class="form-control" @bind="Model.Address" rows="2" placeholder="123 Main St, City, State ZIP"></textarea>
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ValidateEmail(Model.Email);
            if (!emailValid)
            {
                ErrorMessage = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}

@using sv_149b435869b64d94925f11192099711f.Models

<h3>Work History</h3>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h5 class="card-title mb-0">Position @(index + 1)</h5>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company *</label>
                    <input class="form-control" @bind="entry.Company" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title *</label>
                    <input class="form-control" @bind="entry.Title" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date *</label>
                    <input type="date" class="form-control" @bind="entry.StartDate" />
                </div>
                <div class="col-md-4">
                    <div class="form-check mt-4">
                        <input type="checkbox" class="form-check-input" id="current-@index"
                               @bind="entry.IsCurrent" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
                @if (!entry.IsCurrent)
                {
                    <div class="col-md-4">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" @bind="entry.EndDate" />
                    </div>
                }
            </div>

            <div class="mb-2">
                <label class="form-label">Description *</label>
                <textarea class="form-control" @bind="entry.Description" rows="3"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Another Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index) => Entries.RemoveAt(index);

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                string.IsNullOrWhiteSpace(entry.Description))
            {
                ErrorMessage = "Company, job title, and description are required for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

