    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnNavigate { get; set; }

    private string GetStatus(int step) =>
        step == CurrentStep ? "active" :
        step < CurrentStep ? "completed" : "future";

    private async Task OnStepClicked(int step)
    {
        if (step < CurrentStep)
            await OnNavigate.InvokeAsync(step);
    }
}
