        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "Please write a cover letter.";
            return;
        }

        if (CoverLetter.Length > MaxCharacters)
        {
            ErrorMessage = $"Cover letter must be {MaxCharacters} characters or fewer.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}
