{"file_text": ".step-indicator {
    display: flex;
    align-items: center;
    gap: 0;
    padding: 1rem 0;
    flex-wrap: wrap;
}

.step-indicator .step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    background: none;
    border: none;
    padding: 0.5rem 0.75rem;
    cursor: pointer;
    font-size: 0.9rem;
    color: #6c757d;
    transition: color 0.2s;
}

.step-indicator .step:disabled {
    cursor: default;
}

.step-indicator .step.active {
    color: #0d6efd;
    font-weight: 600;
}

.step-indicator .step.completed {
    color: #198754;
}

.step-indicator .step.future {
    color: #adb5bd;
}

.step-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.8rem;
    height: 1.8rem;
    border-radius: 50%;
    font-size: 0.85rem;
    font-weight: 600;
    flex-shrink: 0;
}

.step.active .step-badge {
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-badge {
    background: #198754;
    color: #fff;
}

.step.future .step-badge {
    background: #e9ecef;
    color: #adb5bd;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background: #dee2e6;
    flex-shrink: 0;
}

.step-connector.completed {
    background: #198754;
}
