+            <span class="step-connector @(stepIndex < CurrentStep ? "completed" : "")"></span>
+        }
+    }
+</nav>
+
+@code {
+    private static readonly string[] StepNames =
+        { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
+
+    [Parameter, EditorRequired] public int CurrentStep { get; set; }
+    [Parameter, EditorRequired] public EventCallback<int> OnNavigate { get; set; }
+
+    private string GetStatus(int step) =>
+        step == CurrentStep ? "active" :
+        step < CurrentStep ? "completed" : "future";
+
+    private async Task OnStepClicked(int step)
+    {
+        if (step < CurrentStep)
+            await OnNavigate.InvokeAsync(step);
+    }
+}
+

toolArgs.file_text:
@using sv_149b435869b64d94925f11192099711f.Models

<h3>Work History</h3>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h5 class="card-title mb-0">Position @(index + 1)</h5>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company *</label>
                    <input class="form-control" @bind="entry.Company" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title *</label>
                    <input class="form-control" @bind="entry.Title" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date *</label>
                    <input type="date" class="form-control" @bind="entry.StartDate" />
                </div>
                <div class="col-md-4">
                    <div class="form-check mt-4">
                        <input type="checkbox" class="form-check-input" id="current-@index"
                               @bind="entry.IsCurrent" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
                @if (!entry.IsCurrent)
                {
                    <div class="col-md-4">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" @bind="entry.EndDate" />
                    </div>
                }
            </div>

            <div class="mb-2">
                <label class="form-label">Description *</label>
                <textarea class="form-control" @bind="entry.Description" rows="3"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Another Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index) => Entries.RemoveAt(index);

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                string.IsNullOrWhiteSpace(entry.Description))
            {
                ErrorMessage = "Company, job title, and description are required for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_149b435869b64d94925f11192099711f.Models

<h3>References</h3>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h5 class="card-title mb-0">Reference @(index + 1)</h5>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name *</label>
                    <input class="form-control" @bind="reference.Name" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship *</label>
                    <input class="form-control" @bind="reference.Relationship" placeholder="e.g. Former Manager" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email *</label>
                    <input type="email" class="form-control" @bind="reference.Email" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone *</label>
                    <input type="tel" class="form-control" @bind="reference.Phone" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference() { if (References.Count < 3) References.Add(new ReferenceModel()); }

    private void RemoveReference(int index) { if (References.Count > 2) References.RemoveAt(index); }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

