@using sv_149b435869b64d94925f11192099711f.Models

<h3>Review & Submit</h3>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Application Submitted!</h4>
        <p>Your application has been received. Your application ID is <strong>@ApplicationId</strong>.</p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Model.Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Model.Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Model.Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Model.Personal.Address</dd>
            </dl>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in Model.WorkEntries)
            {
                <div class="mb-3">
                    <strong>@entry.Title</strong> at <em>@entry.Company</em><br />
                    <small class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    <p class="mt-1 mb-0">@entry.Description</p>
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in Model.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <small>@r.Email · @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@Model.CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEdit { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> SubmitApplication { get; set; } = default!;

    private bool IsSubmitting;
    private bool Submitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;
        try
        {
            ApplicationId = await SubmitApplication();
            Submitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

@page "/apply"
@using sv_149b435869b64d94925f11192099711f.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h2 class="mb-4">Job Application</h2>

<StepIndicator CurrentStep="currentStep" OnNavigate="GoToStep" />

<div class="mt-4">
    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="formModel.Personal"
                              OnNext="NextStep"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;
        case 1:
            <WorkHistoryStep Entries="formModel.WorkEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="formModel.References"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep @bind-CoverLetter="formModel.CoverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Model="formModel"
                        OnBack="PreviousStep"
                        OnEdit="GoToStep"
                        SubmitApplication="SubmitAsync" />
            break;
    }
</div>

@code {
    private int currentStep;
    private readonly ApplicationFormModel formModel = new();

    private void NextStep() => currentStep = Math.Min(currentStep + 1, 4);
    private void PreviousStep() => currentStep = Math.Max(currentStep - 1, 0);
    private void GoToStep(int step) => currentStep = step;

    private async Task<int> SubmitAsync()
    {
        return await ApplicationService.SubmitApplicationAsync(formModel.ToRecord());
    }
}

.step-indicator {
    display: flex;
    align-items: center;
    gap: 0;
    padding: 1rem 0;
    flex-wrap: wrap;
}

.step-indicator .step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    background: none;
    border: none;
    padding: 0.5rem 0.75rem;
    cursor: pointer;
    font-size: 0.9rem;
    color: #6c757d;
    transition: color 0.2s;
}

.step-indicator .step:disabled {
    cursor: default;
}

.step-indicator .step.active {
    color: #0d6efd;
    font-weight: 600;
}

.step-indicator .step.completed {
    color: #198754;
}

.step-indicator .step.future {
    color: #adb5bd;
}

.step-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.8rem;
    height: 1.8rem;
    border-radius: 50%;
    font-size: 0.85rem;
    font-weight: 600;
    flex-shrink: 0;
}

.step.active .step-badge {
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-badge {
    background: #198754;
    color: #fff;
}

.step.future .step-badge {
    background: #e9ecef;
    color: #adb5bd;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background: #dee2e6;
    flex-shrink: 0;
}

.step-connector.completed {
    background: #198754;
}

